{
  "mode": "All",
  "displayName": "Require vCPU-Budget tag on resource groups",
  "description": "Ensures every RG declares its approved vCPU budget for quota tracking",
  "parameters": {},
  "policyRule": {
    "if": {
      "allOf": [
        {
          "field": "type",
          "equals": "Microsoft.Resources/resourceGroups"
        },
        {
          "field": "tags['vCPU-Budget']",
          "exists": "false"
        }
      ]
    },
    "then": {
      "effect": "deny"
    }
  }
}

// subscription-vending.bicep
// Deploys at: tenant scope
targetScope = 'tenant'

@description('Display name for the new subscription')
param subscriptionDisplayName string

@description('EA billing account name')
param billingAccountName string

@description('EA enrollment account object ID')
param enrollmentAccountObjectId string

@description('Environment tag: dev | staging | prod')
@allowed(['dev', 'staging', 'prod'])
param environment string = 'dev'

resource newSubscription 'Microsoft.Subscription/aliases@2021-10-01' = {
  name: '${subscriptionDisplayName}-alias'
  properties: {
    workload: environment == 'prod' ? 'Production' : 'DevTest'
    displayName: subscriptionDisplayName
    billingScope: '/providers/Microsoft.Billing/billingAccounts/${billingAccountName}/enrollmentAccounts/${enrollmentAccountObjectId}'
    additionalProperties: {
      subscriptionTenantId: tenant().tenantId
      tags: {
        Environment: environment
        ManagedBy: 'SubscriptionVending'
        CreatedDate: utcNow('yyyy-MM-dd')
      }
    }
  }
}

output subscriptionId string = newSubscription.properties.subscriptionId

def poll_quota_request_status(subscription_id: str, request_id: str):
    quota_client = AzureQuotaExtensionAPI(credential, subscription_id)
    request = quota_client.quota_request_status.get(
        id=request_id,
        scope=f"subscriptions/{subscription_id}/providers/Microsoft.Compute/locations/eastus"
    )
    return {
        "id": request.id,
        "state": request.properties.provisioning_state,
        "message": request.properties.message,
        "submitted": str(request.properties.request_submit_time),
    }
